"use client";

import { useState } from "react";
import { Zap, PlayCircle, Plus, ArrowLeft, ArrowRight, RefreshCw, Bookmark, Share2, MoreHorizontal, FileText, CheckCircle2, RotateCw } from "lucide-react";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";

export default function FlashcardsPage() {
    const [flipped, setFlipped] = useState(false);
    const [cardIndex, setCardIndex] = useState(0);

    const cards = [
        {
            front: "Define the Schrödinger Wave Equation in terms of system probability.",
            back: "It is a mathematical expression that describes the quantum state of a physical system as a function of time and space, fundamentally representing the probability density of finding a particle.",
            formula: "Ĥψ = Eψ"
        },
        {
            front: "What is quantum entanglement?",
            back: "A physical phenomenon that occurs when a group of particles are generated, interact, or share spatial proximity in a way such that the quantum state of each particle of the group cannot be described independently of the state of the others.",
            formula: null
        }
    ];

    const handleNext = () => {
        setFlipped(false);
        setTimeout(() => {
            setCardIndex((prev) => (prev + 1) % cards.length);
        }, 300); // Wait for un-flip animation
    };

    const handlePrev = () => {
        setFlipped(false);
        setTimeout(() => {
            setCardIndex((prev) => (prev - 1 + cards.length) % cards.length);
        }, 300);
    };

    return (
        <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500 pb-12">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between md:items-center gap-4 bg-card p-6 border border-border rounded-2xl shadow-sm">
                <div className="flex items-center gap-4">
                    <Link href="/dashboard" className="w-10 h-10 bg-secondary/50 rounded-xl flex items-center justify-center hover:bg-secondary transition-colors text-muted-foreground hover:text-foreground">
                        <ArrowLeft className="w-5 h-5" />
                    </Link>
                    <div>
                        <div className="flex items-center gap-2">
                            <Zap className="w-5 h-5 text-amber-500 fill-amber-500/20" />
                            <h1 className="text-xl font-bold text-foreground">Flashcard Mastery</h1>
                        </div>
                        <p className="text-sm text-muted-foreground mt-0.5 font-medium">Session: Quantum Mechanics</p>
                    </div>
                </div>

                <div className="flex items-center justify-between md:justify-end gap-6 w-full md:w-auto">
                    <div className="text-right">
                        <p className="text-[11px] text-muted-foreground uppercase font-semibold tracking-wider mb-1">Progress</p>
                        <p className="text-xl font-bold text-foreground font-mono">{cardIndex + 1} / {cards.length}</p>
                    </div>
                    <div className="flex items-center gap-2">
                        <button className="w-10 h-10 flex items-center justify-center border border-border bg-background rounded-lg hover:bg-secondary transition-colors text-muted-foreground hover:text-foreground">
                            <Share2 className="w-4 h-4" />
                        </button>
                        <button className="w-10 h-10 flex items-center justify-center border border-border bg-background rounded-lg hover:bg-secondary transition-colors text-muted-foreground hover:text-foreground">
                            <MoreHorizontal className="w-4 h-4" />
                        </button>
                    </div>
                </div>
            </div>

            {/* Flashcard Component */}
            <div className="flex flex-col items-center justify-center w-full min-h-[400px]">
                <div className="relative w-full max-w-2xl h-[400px] perspective-1000 group cursor-pointer" onClick={() => setFlipped(!flipped)}>
                    <motion.div
                        initial={false}
                        animate={{ rotateY: flipped ? 180 : 0 }}
                        transition={{ duration: 0.6, type: "spring", stiffness: 200, damping: 20 }}
                        className="w-full h-full relative preserve-3d"
                        style={{ transformStyle: "preserve-3d" }}
                    >
                        {/* Front Side */}
                        <div
                            className="absolute inset-0 backface-hidden flex flex-col items-center justify-center p-12 bg-card border-[1.5px] border-border rounded-3xl shadow-sm group-hover:shadow-md transition-shadow"
                            style={{ backfaceVisibility: "hidden" }}
                        >
                            <div className="absolute top-8 left-8 flex items-center gap-2">
                                <span className="w-2 h-2 rounded-full bg-amber-500 animate-pulse" />
                                <span className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">Question</span>
                            </div>
                            <div className="absolute top-8 right-8 text-muted-foreground">
                                <Bookmark className="w-5 h-5 hover:text-primary transition-colors hover:fill-primary/20" />
                            </div>

                            <h2 className="text-2xl md:text-3xl font-bold text-foreground text-center leading-[1.4] font-serif max-w-lg">
                                {cards[cardIndex].front}
                            </h2>

                            <div className="absolute bottom-8 left-0 right-0 flex justify-center text-muted-foreground/50 group-hover:text-primary/70 transition-colors">
                                <span className="text-xs font-medium uppercase tracking-widest flex items-center gap-2">
                                    <RotateCw className="w-3.5 h-3.5" /> Click to reveal
                                </span>
                            </div>
                        </div>

                        {/* Back Side */}
                        <div
                            className="absolute inset-0 backface-hidden flex flex-col items-center justify-center p-12 bg-foreground text-background border-[1.5px] border-foreground rounded-3xl shadow-xl overflow-hidden"
                            style={{ backfaceVisibility: "hidden", transform: "rotateY(180deg)" }}
                        >
                            <div className="absolute top-8 left-8 flex items-center gap-2">
                                <span className="w-2 h-2 rounded-full bg-emerald-500" />
                                <span className="text-[11px] font-semibold uppercase tracking-wider text-background/50">Answer</span>
                            </div>

                            <div className="flex flex-col items-center justify-center flex-1 space-y-6 max-w-xl">
                                <p className="text-xl md:text-2xl font-medium leading-relaxed font-serif text-center text-background text-balance">
                                    {cards[cardIndex].back}
                                </p>

                                {cards[cardIndex].formula && (
                                    <div className="px-6 py-4 bg-background/10 rounded-xl font-mono text-lg border border-background/20 mt-4 shadow-inner text-white">
                                        {cards[cardIndex].formula}
                                    </div>
                                )}
                            </div>

                            {/* Decorative glow */}
                            <div className="absolute -bottom-24 -right-24 w-64 h-64 bg-primary/20 blur-[100px] rounded-full pointer-events-none" />
                        </div>
                    </motion.div>
                </div>
            </div>

            {/* Navigation & Controls */}
            <div className="flex flex-col sm:flex-row items-center justify-between gap-6 max-w-2xl mx-auto w-full px-4">

                <button className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-muted-foreground hover:text-foreground hover:bg-secondary/50 rounded-lg transition-colors border border-transparent hover:border-border/50">
                    <RefreshCw className="w-4 h-4" /> Restart
                </button>

                <div className="flex items-center gap-4">
                    <button
                        onClick={handlePrev}
                        className="w-12 h-12 flex items-center justify-center bg-card border border-border rounded-full hover:bg-secondary transition-colors text-foreground hover:scale-105"
                    >
                        <ArrowLeft className="w-5 h-5" />
                    </button>

                    <button
                        onClick={handleNext}
                        className="w-14 h-14 flex items-center justify-center bg-primary text-primary-foreground rounded-full hover:bg-primary/90 transition-transform hover:scale-105 shadow-md shadow-primary/20"
                    >
                        <ArrowRight className="w-6 h-6" />
                    </button>
                </div>

                <div className="hidden sm:block w-[90px]" /> {/* Spacer for centering */}
            </div>

        </div>
    );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import {
    BookOpen, LayoutDashboard, Upload, FileText, Zap, BrainCircuit,
    Calendar, History, Settings, LogOut, Search, MessageSquare,
    MoreHorizontal, PlusCircle
} from "lucide-react";
import { useState, useEffect } from "react";
import { CommandPalette } from "@/components/CommandPalette";

export default function DashboardLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const pathname = usePathname();
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
    }, []);

    const sidebarItems = [
        { icon: LayoutDashboard, label: "Dashboard", href: "/dashboard" },
        { icon: Upload, label: "Upload Lecture", href: "/dashboard/upload" },
        { icon: FileText, label: "AI Notes", href: "/dashboard/notes" },
        { icon: Zap, label: "Flashcards", href: "/dashboard/flashcards" },
        { icon: BrainCircuit, label: "Quizzes", href: "/dashboard/quizzes" },
        { icon: MessageSquare, label: "Lecture Chat", href: "/dashboard/chat" },
        { icon: Calendar, label: "Study Planner", href: "/dashboard/planner" },
        { icon: History, label: "History", href: "/dashboard/history" },
        { icon: Settings, label: "Settings", href: "/dashboard/settings" },
    ];

    if (!mounted) return null;

    return (
        <div className="flex h-screen bg-background text-foreground overflow-hidden font-sans">
            {/* Command Palette Global Overlay */}
            <CommandPalette />

            {/* Notch / Notion Style Sidebar */}
            <aside className="w-[260px] bg-secondary/30 border-r border-border flex flex-col transition-all duration-300">

                {/* Workspace Switcher Area */}
                <div className="h-12 flex items-center px-4 mt-2 mb-4 hover:bg-secondary/50 cursor-pointer transition-colors mx-2 rounded-md">
                    <div className="flex items-center gap-2 w-full">
                        <div className="w-6 h-6 bg-primary rounded shadow-sm flex items-center justify-center text-primary-foreground text-xs font-bold">
                            PM
                        </div>
                        <span className="text-sm font-semibold truncate flex-1">Pradeep's Workspace</span>
                        <MoreHorizontal className="w-4 h-4 text-muted-foreground" />
                    </div>
                </div>

                {/* Global Search Button */}
                <div className="px-4 mb-6">
                    <button
                        onClick={() => {
                            document.dispatchEvent(new KeyboardEvent('keydown', { key: 'k', metaKey: true }));
                        }}
                        className="w-full flex items-center gap-2 px-2 py-1.5 text-sm text-muted-foreground border border-border/50 bg-background/50 rounded-md hover:bg-secondary transition-colors shadow-sm"
                    >
                        <Search className="w-4 h-4" />
                        <span className="flex-1 text-left">Search</span>
                        <kbd className="hidden sm:inline-block px-1.5 py-0.5 text-[10px] font-mono font-medium rounded bg-secondary text-muted-foreground border border-border">
                            ⌘K
                        </kbd>
                    </button>
                </div>

                <div className="px-2 pb-2">
                    <div className="text-xs font-semibold text-muted-foreground px-2 mb-2">WORKSPACE</div>
                </div>

                {/* Navigation */}
                <nav className="flex-1 overflow-y-auto px-2 space-y-[2px]">
                    {sidebarItems.map((item, i) => {
                        const isActive = pathname === item.href;
                        return (
                            <Link
                                key={i}
                                href={item.href}
                                className={`group flex items-center gap-2.5 px-2 py-1.5 rounded-md transition-colors text-sm font-medium ${isActive
                                        ? "bg-secondary text-foreground"
                                        : "text-muted-foreground hover:bg-secondary/60 hover:text-foreground"
                                    }`}
                            >
                                <item.icon className={`w-[18px] h-[18px] ${isActive ? 'text-primary' : 'text-muted-foreground'}`} />
                                <span>{item.label}</span>
                            </Link>
                        );
                    })}
                </nav>

                {/* Bottom Section */}
                <div className="p-4 border-t border-border/50 bg-secondary/10">
                    <div className="mb-3 space-y-1">
                        <div className="flex justify-between items-center text-xs font-medium text-muted-foreground">
                            <span>AI Usage (Free)</span>
                            <span>7/10</span>
                        </div>
                        <div className="w-full h-1.5 bg-muted rounded-full overflow-hidden">
                            <div className="w-[70%] h-full bg-primary" />
                        </div>
                    </div>

                    <Link href="/dashboard/settings/billing" className="flex items-center justify-center gap-2 w-full py-2 bg-background border border-border rounded-md text-sm font-medium hover:bg-secondary/50 transition-colors shadow-sm">
                        <PlusCircle className="w-4 h-4" />
                        Upgrade to Pro
                    </Link>

                    <button className="flex items-center gap-2 px-2 mt-4 text-sm text-muted-foreground hover:text-red-500 font-medium w-full transition-colors">
                        <LogOut className="w-4 h-4" />
                        <span>Log out</span>
                    </button>
                </div>
            </aside>

            {/* Main Content Area */}
            <main className="flex-1 flex flex-col min-w-0 bg-background relative">
                {/* Top bar */}
                <header className="h-12 flex items-center px-6 sticky top-0 bg-background/80 backdrop-blur-sm z-10 border-b border-transparent transition-colors">
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <BookOpen className="w-4 h-4" />
                        <span>/</span>
                        <span className="capitalize">{pathname.split('/').pop() || 'Dashboard'}</span>
                    </div>
                </header>

                {/* Page Content */}
                <div className="flex-1 overflow-y-auto w-full p-8 md:p-12">
                    <div className="max-w-5xl mx-auto w-full">
                        {children}
                    </div>
                </div>
            </main>
        </div>
    );
}

"use client";

import { BrainCircuit, Clock, CheckCircle2, XCircle, ArrowRight, ArrowLeft, RefreshCw, Trophy, FileText, Check, X, AlertCircle } from "lucide-react";
import Link from "next/link";
import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

export default function QuizzesPage() {
    const [selectedOption, setSelectedOption] = useState<string | null>(null);
    const [isAnswered, setIsAnswered] = useState(false);

    const handleOptionSelect = (id: string) => {
        if (isAnswered) return;
        setSelectedOption(id);
    };

    const submitAnswer = () => {
        if (selectedOption) {
            setIsAnswered(true);
        }
    };

    const options = [
        { id: "a", text: "Quantum Entanglement", description: "Interaction between two distant particles." },
        { id: "b", text: "Linear Superposition", description: "A system in all possible theoretical states.", correct: true },
        { id: "c", text: "Wave Function Collapse", description: "The transition from state to observation." },
        { id: "d", text: "Photoelectric Effect", description: "Emission of electrons from material." }
    ];

    return (
        <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500 pb-12">
            {/* Quiz Header */}
            <div className="bg-card p-6 rounded-2xl border border-border flex flex-col md:flex-row justify-between md:items-center gap-6 shadow-sm">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-primary/10 rounded-xl flex items-center justify-center shrink-0">
                        <BrainCircuit className="text-primary w-6 h-6" />
                    </div>
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <span className="px-2 py-0.5 bg-secondary text-primary text-[10px] uppercase font-bold tracking-wider rounded">Quiz Mode</span>
                            <h1 className="text-lg font-bold text-foreground leading-tight">Physics 101: Quantum Mechanics</h1>
                        </div>
                        <p className="text-sm text-muted-foreground font-medium">Session generated from "Quantum Mechanics Lect 1"</p>
                    </div>
                </div>

                <div className="flex items-center gap-6 px-4 py-2 bg-secondary/50 rounded-xl border border-border/50 self-start md:self-auto">
                    <div className="flex items-center gap-2">
                        <Clock className="w-4 h-4 text-emerald-500 animate-pulse" />
                        <span className="text-sm font-semibold text-foreground font-mono">14:52</span>
                    </div>
                    <div className="w-px h-6 bg-border" />
                    <div className="flex items-center gap-2">
                        <Trophy className="w-4 h-4 text-amber-500" />
                        <span className="text-sm font-semibold text-foreground font-mono">08/10</span>
                    </div>
                </div>
            </div>

            {/* Main Quiz Area */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* Content Area */}
                <div className="lg:col-span-2 space-y-6 h-full flex flex-col">
                    <div className="bg-card border border-border rounded-2xl p-8 flex-1 shadow-sm relative overflow-hidden flex flex-col">

                        <div className="mb-8">
                            <div className="flex items-center justify-between mb-4">
                                <span className="text-xs font-bold tracking-wider text-muted-foreground uppercase">Question 3 of 10</span>
                                <span className="text-xs font-semibold px-2 py-1 bg-secondary rounded text-primary">Multiple Choice</span>
                            </div>
                            <h2 className="text-2xl font-bold text-foreground leading-snug font-serif">
                                What phenomenon describes a particle representing multiple states simultaneously before observation?
                            </h2>
                        </div>

                        <div className="space-y-3 flex-1">
                            {options.map((option) => {
                                const isSelected = selectedOption === option.id;
                                const showCorrect = isAnswered && option.correct;
                                const showIncorrect = isAnswered && isSelected && !option.correct;

                                let buttonClass = "border-border hover:border-primary/50 hover:bg-secondary/30";
                                let iconClass = "bg-secondary text-muted-foreground";

                                if (isSelected && !isAnswered) {
                                    buttonClass = "border-primary bg-primary/5 ring-1 ring-primary/20";
                                    iconClass = "bg-primary text-primary-foreground";
                                } else if (showCorrect) {
                                    buttonClass = "border-emerald-500 bg-emerald-500/10 ring-1 ring-emerald-500/20";
                                    iconClass = "bg-emerald-500 text-white";
                                } else if (showIncorrect) {
                                    buttonClass = "border-red-500 bg-red-500/10 ring-1 ring-red-500/20";
                                    iconClass = "bg-red-500 text-white";
                                }

                                return (
                                    <button
                                        key={option.id}
                                        onClick={() => handleOptionSelect(option.id)}
                                        disabled={isAnswered}
                                        className={`w-full flex items-start gap-4 p-4 border rounded-xl text-left transition-all ${buttonClass}`}
                                    >
                                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-sm shrink-0 uppercase transition-colors shrink-0 ${iconClass}`}>
                                            {showCorrect ? <Check className="w-4 h-4" /> : showIncorrect ? <X className="w-4 h-4" /> : option.id}
                                        </div>
                                        <div className="flex-1 mt-1">
                                            <p className={`font-semibold text-base ${showCorrect ? 'text-emerald-700 dark:text-emerald-400' : showIncorrect ? 'text-red-700 dark:text-red-400' : 'text-foreground'}`}>
                                                {option.text}
                                            </p>
                                            <p className="text-sm text-muted-foreground mt-1">
                                                {option.description}
                                            </p>
                                        </div>
                                    </button>
                                );
                            })}
                        </div>

                        {/* Explanation (Expanded on Answer) */}
                        <AnimatePresence>
                            {isAnswered && (
                                <motion.div
                                    initial={{ opacity: 0, height: 0, marginTop: 0 }}
                                    animate={{ opacity: 1, height: "auto", marginTop: 24 }}
                                    className="p-5 bg-secondary/50 rounded-xl border border-border/70 overflow-hidden"
                                >
                                    <div className="flex gap-3">
                                        <div className="mt-0.5 shrink-0">
                                            <AlertCircle className="w-5 h-5 text-primary" />
                                        </div>
                                        <div>
                                            <p className="text-sm font-semibold text-foreground mb-1">Explanation</p>
                                            <p className="text-sm text-muted-foreground leading-relaxed font-serif">
                                                Linear Superposition is a core principle of quantum mechanics. It states that any two (or more) quantum states can be added together and result in another valid quantum state. This superposition is maintained until the system is observed or measured, at which point the wave function collapses.
                                            </p>
                                        </div>
                                    </div>
                                </motion.div>
                            )}
                        </AnimatePresence>

                        <div className="flex justify-between items-center pt-6 mt-6 border-t border-border">
                            <button className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-muted-foreground hover:text-foreground hover:bg-secondary rounded-lg transition-colors">
                                <ArrowLeft className="w-4 h-4" /> Previous
                            </button>

                            {!isAnswered ? (
                                <button
                                    onClick={submitAnswer}
                                    disabled={!selectedOption}
                                    className="flex items-center gap-2 px-6 py-2.5 bg-foreground text-background rounded-lg text-sm font-medium hover:bg-foreground/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                    Check Answer
                                </button>
                            ) : (
                                <button className="flex items-center gap-2 px-6 py-2.5 bg-primary text-primary-foreground rounded-lg text-sm font-medium hover:bg-primary/90 transition-colors shadow-sm">
                                    Next Question <ArrowRight className="w-4 h-4" />
                                </button>
                            )}
                        </div>
                    </div>
                </div>

                {/* Sidebar Nav */}
                <div className="lg:col-span-1 space-y-6">
                    <div className="bg-card border border-border rounded-2xl p-6 shadow-sm">
                        <h3 className="font-semibold text-foreground text-sm mb-4 flex items-center gap-2">
                            <BrainCircuit className="w-4 h-4 text-primary" /> Session Overview
                        </h3>

                        {/* Status Bubbles */}
                        <div className="grid grid-cols-5 gap-2 mb-6">
                            {[...Array(10)].map((_, i) => {
                                let stateClass = "border border-border text-muted-foreground bg-background hover:bg-secondary";
                                if (i < 2) stateClass = "bg-emerald-500/10 text-emerald-500 border border-emerald-500/20"; // correct
                                else if (i === 2) stateClass = "bg-primary text-primary-foreground font-bold shadow-sm"; // active

                                return (
                                    <button
                                        key={i}
                                        className={`aspect-square rounded-lg flex items-center justify-center text-xs font-semibold cursor-pointer transition-colors ${stateClass}`}
                                    >
                                        {i + 1}
                                    </button>
                                );
                            })}
                        </div>

                        {/* Legends */}
                        <div className="space-y-3 pt-4 border-t border-border/50">
                            {[
                                { label: "Correct", count: 2, icon: CheckCircle2, color: "text-emerald-500" },
                                { label: "Incorrect", count: 0, icon: XCircle, color: "text-red-500" },
                                { label: "Remaining", count: 8, icon: RefreshCw, color: "text-muted-foreground" }
                            ].map((stat, i) => (
                                <div key={i} className="flex justify-between items-center text-sm">
                                    <div className="flex items-center gap-2.5">
                                        <stat.icon className={`w-4 h-4 ${stat.color}`} />
                                        <span className="text-muted-foreground font-medium">{stat.label}</span>
                                    </div>
                                    <span className="text-foreground font-semibold font-mono">{stat.count}</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="bg-gradient-to-b from-primary/10 to-transparent border border-primary/20 rounded-2xl p-6 text-center space-y-3 relative overflow-hidden">
                        <Trophy className="w-10 h-10 text-amber-500 mx-auto" />
                        <h4 className="font-semibold text-foreground">Current Streak: 2</h4>
                        <p className="text-xs text-muted-foreground leading-relaxed">
                            You're doing great! Answer 3 more correctly to increase your multiplier.
                        </p>
                    </div>
                </div>

            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Upload, Youtube, ArrowRight, Loader2, Link as LinkIcon, Files, Presentation, CheckCircle2, Circle, Sparkles, Video, FileAudio, FileText } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

export default function UploadPage() {
    const [uploadState, setUploadState] = useState<"idle" | "processing" | "done">("idle");
    const [progress, setProgress] = useState(0);
    const [activeStep, setActiveStep] = useState(0);
    const [fileName, setFileName] = useState("");

    const steps = [
        "Downloading video",
        "Extracting audio",
        "Transcribing lecture",
        "Generating notes",
        "Creating flashcards",
        "Generating quiz"
    ];

    const simulateUpload = () => {
        setFileName("Introduction to Neural Networks.mp4");
        setUploadState("processing");
        setProgress(0);
        setActiveStep(0);
    };

    useEffect(() => {
        if (uploadState === "processing") {
            const interval = setInterval(() => {
                setProgress(p => {
                    const newP = p + 2;
                    if (newP >= 100) {
                        clearInterval(interval);
                        setUploadState("done");
                        return 100;
                    }
                    // Update active step based on progress
                    const newStep = Math.floor((newP / 100) * steps.length);
                    if (newStep < steps.length) {
                        setActiveStep(newStep);
                    }
                    return newP;
                });
            }, 200);
            return () => clearInterval(interval);
        }
    }, [uploadState, steps.length]);

    return (
        <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in duration-500 pb-12">

            <div className="mb-8">
                <h1 className="text-3xl font-bold tracking-tight text-foreground mb-2">Upload Material</h1>
                <p className="text-muted-foreground">Upload your lecture, video, or paste a YouTube link to generate your study materials.</p>
            </div>

            <AnimatePresence mode="wait">
                {uploadState === "idle" && (
                    <motion.div
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.98 }}
                        className="grid grid-cols-1 md:grid-cols-2 gap-6"
                    >
                        {/* Drag & Drop Area */}
                        <div
                            onClick={simulateUpload}
                            className="bg-card border-2 border-dashed border-border/60 hover:border-primary/50 hover:bg-secondary/30 rounded-2xl p-10 flex flex-col items-center justify-center text-center transition-all cursor-pointer group shadow-sm min-h-[300px]"
                        >
                            <div className="w-16 h-16 bg-background border border-border rounded-2xl flex items-center justify-center mb-6 shadow-sm group-hover:scale-105 transition-transform">
                                <Upload className="w-8 h-8 text-primary" />
                            </div>
                            <h3 className="font-semibold text-foreground text-lg mb-2">Click or drag file to upload</h3>
                            <p className="text-sm text-muted-foreground mb-6 max-w-[250px]">
                                SVG, PNG, JPG or GIF (max. 800x400px)
                            </p>

                            <div className="flex gap-4">
                                <div className="flex items-center gap-1.5 text-xs font-medium text-muted-foreground bg-background border border-border px-2.5 py-1 rounded-md">
                                    <Video className="w-3.5 h-3.5" /> MP4
                                </div>
                                <div className="flex items-center gap-1.5 text-xs font-medium text-muted-foreground bg-background border border-border px-2.5 py-1 rounded-md">
                                    <FileAudio className="w-3.5 h-3.5" /> MP3
                                </div>
                                <div className="flex items-center gap-1.5 text-xs font-medium text-muted-foreground bg-background border border-border px-2.5 py-1 rounded-md">
                                    <FileText className="w-3.5 h-3.5" /> PDF
                                </div>
                            </div>
                        </div>

                        {/* YouTube Link */}
                        <div className="bg-card border border-border rounded-2xl p-8 flex flex-col justify-between shadow-sm min-h-[300px]">
                            <div>
                                <div className="flex items-center gap-3 mb-6">
                                    <div className="w-10 h-10 bg-red-500/10 rounded-xl flex items-center justify-center">
                                        <Youtube className="text-red-500 w-5 h-5" />
                                    </div>
                                    <h3 className="font-semibold text-foreground text-lg">YouTube Link</h3>
                                </div>
                                <p className="text-sm text-muted-foreground mb-6">
                                    Paste a YouTube URL to automatically download and process the video.
                                </p>

                                <div className="space-y-3">
                                    <div className="relative flex items-center">
                                        <LinkIcon className="absolute left-3 w-4 h-4 text-muted-foreground" />
                                        <input
                                            type="text"
                                            placeholder="https://youtube.com/watch?v=..."
                                            className="w-full bg-background border border-border rounded-xl pl-10 pr-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all text-foreground"
                                        />
                                    </div>
                                </div>
                            </div>

                            <button
                                onClick={simulateUpload}
                                className="w-full py-3 bg-foreground text-background rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-foreground/90 transition-colors mt-6"
                            >
                                Process Video <ArrowRight className="w-4 h-4" />
                            </button>
                        </div>
                    </motion.div>
                )}

                {(uploadState === "processing" || uploadState === "done") && (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="bg-card border border-border rounded-2xl p-8 shadow-sm"
                    >
                        <div className="flex items-start justify-between mb-8">
                            <div className="flex items-center gap-4">
                                <div className={`w-12 h-12 rounded-xl flex items-center justify-center border ${uploadState === 'done' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-primary/10 border-primary/20 text-primary'}`}>
                                    {uploadState === 'done' ? <CheckCircle2 className="w-6 h-6" /> : <Loader2 className="w-6 h-6 animate-spin" />}
                                </div>
                                <div>
                                    <h3 className="font-semibold text-foreground text-lg">{fileName}</h3>
                                    <p className="text-sm border-t border-transparent text-muted-foreground mt-0.5">
                                        {uploadState === 'done' ? 'Processing complete' : 'AI is processing your material...'}
                                    </p>
                                </div>
                            </div>
                            <span className="text-2xl font-bold tabular-nums text-foreground">{progress}%</span>
                        </div>

                        {/* Progress Bar */}
                        <div className="w-full h-2 bg-secondary rounded-full overflow-hidden mb-8">
                            <motion.div
                                className={`h-full ${uploadState === 'done' ? 'bg-emerald-500' : 'bg-primary'}`}
                                initial={{ width: 0 }}
                                animate={{ width: `${progress}%` }}
                                transition={{ ease: "linear" }}
                            />
                        </div>

                        {/* Pipeline Steps */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-y-6 gap-x-4 p-6 bg-background rounded-xl border border-border/50">
                            {steps.map((step, index) => {
                                let status = "pending";
                                if (uploadState === "done" || index < activeStep) status = "complete";
                                if (uploadState === "processing" && index === activeStep) status = "active";

                                return (
                                    <div key={index} className="flex items-center gap-3">
                                        {status === "complete" && <CheckCircle2 className="w-5 h-5 text-emerald-500 shrink-0" />}
                                        {status === "active" && <Loader2 className="w-5 h-5 text-primary animate-spin shrink-0" />}
                                        {status === "pending" && <Circle className="w-5 h-5 text-muted-foreground/30 shrink-0" />}

                                        <span className={`text-sm font-medium ${status === "complete" ? "text-foreground" :
                                                status === "active" ? "text-primary" : "text-muted-foreground"
                                            }`}>
                                            {step}
                                        </span>
                                    </div>
                                );
                            })}
                        </div>

                        {uploadState === "done" && (
                            <motion.div
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="mt-8 flex justify-end"
                            >
                                <button className="py-2.5 px-6 bg-primary text-primary-foreground rounded-lg font-medium hover:bg-primary/90 transition-colors shadow-sm flex items-center gap-2">
                                    <Sparkles className="w-4 h-4" /> View WorkSpace
                                </button>
                            </motion.div>
                        )}
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

"use client";

import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { Command } from "cmdk";
import { Upload, FileText, Zap, BrainCircuit, Search, LogOut, Settings, LayoutDashboard } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

export function CommandPalette() {
    const [open, setOpen] = useState(false);
    const router = useRouter();

    useEffect(() => {
        const down = (e: KeyboardEvent) => {
            if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
                e.preventDefault();
                setOpen((open) => !open);
            }
        };

        document.addEventListener("keydown", down);
        return () => document.removeEventListener("keydown", down);
    }, []);

    const runCommand = (command: () => void) => {
        setOpen(false);
        command();
    };

    return (
        <AnimatePresence>
            {open && (
                <React.Fragment>
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={() => setOpen(false)}
                        className="fixed inset-0 bg-background/80 backdrop-blur-sm z-50 transition-opacity"
                    />
                    <div className="fixed inset-0 z-50 flex items-start justify-center pt-32 pointer-events-none">
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95, y: -20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95, y: -20 }}
                            transition={{ duration: 0.2, ease: "easeOut" }}
                            className="w-full max-w-xl pointer-events-auto"
                        >
                            <Command className="flex flex-col overflow-hidden rounded-xl bg-card border border-border shadow-2xl">
                                <div className="flex items-center border-b border-border px-3">
                                    <Search className="mr-2 h-4 w-4 shrink-0 text-muted-foreground" />
                                    <Command.Input
                                        placeholder="Type a command or search..."
                                        className="flex h-12 w-full rounded-md bg-transparent py-3 text-sm outline-none placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:opacity-50 text-foreground"
                                        autoFocus
                                    />
                                </div>
                                <Command.List className="max-h-[300px] overflow-y-auto overflow-x-hidden p-2">
                                    <Command.Empty className="py-6 text-center text-sm text-muted-foreground">
                                        No results found.
                                    </Command.Empty>

                                    <Command.Group heading="Quick Actions" className="px-2 text-xs font-semibold text-muted-foreground mb-2 mt-2">
                                        <Command.Item
                                            onSelect={() => runCommand(() => router.push("/dashboard/upload"))}
                                            className="flex cursor-pointer items-center rounded-md px-2 py-2 text-sm hover:bg-secondary aria-selected:bg-secondary text-foreground"
                                        >
                                            <Upload className="mr-2 h-4 w-4" />
                                            <span>Upload Lecture</span>
                                            <span className="ml-auto text-xs text-muted-foreground">⌘ U</span>
                                        </Command.Item>
                                        <Command.Item
                                            onSelect={() => runCommand(() => router.push("/dashboard/notes"))}
                                            className="flex cursor-pointer items-center rounded-md px-2 py-2 text-sm hover:bg-secondary aria-selected:bg-secondary text-foreground"
                                        >
                                            <FileText className="mr-2 h-4 w-4" />
                                            <span>Generate Notes</span>
                                        </Command.Item>
                                        <Command.Item
                                            onSelect={() => runCommand(() => router.push("/dashboard/flashcards"))}
                                            className="flex cursor-pointer items-center rounded-md px-2 py-2 text-sm hover:bg-secondary aria-selected:bg-secondary text-foreground"
                                        >
                                            <Zap className="mr-2 h-4 w-4" />
                                            <span>Generate Flashcards</span>
                                        </Command.Item>
                                        <Command.Item
                                            onSelect={() => runCommand(() => router.push("/dashboard/quizzes"))}
                                            className="flex cursor-pointer items-center rounded-md px-2 py-2 text-sm hover:bg-secondary aria-selected:bg-secondary text-foreground"
                                        >
                                            <BrainCircuit className="mr-2 h-4 w-4" />
                                            <span>Generate Quiz</span>
                                        </Command.Item>
                                    </Command.Group>

                                    <Command.Separator className="h-px bg-border my-2" />

                                    <Command.Group heading="Navigation" className="px-2 text-xs font-semibold text-muted-foreground mb-2">
                                        <Command.Item
                                            onSelect={() => runCommand(() => router.push("/dashboard"))}
                                            className="flex cursor-pointer items-center rounded-md px-2 py-2 text-sm hover:bg-secondary aria-selected:bg-secondary text-foreground"
                                        >
                                            <LayoutDashboard className="mr-2 h-4 w-4" />
                                            <span>Go to Dashboard</span>
                                        </Command.Item>
                                        <Command.Item
                                            onSelect={() => runCommand(() => router.push("/dashboard/settings"))}
                                            className="flex cursor-pointer items-center rounded-md px-2 py-2 text-sm hover:bg-secondary aria-selected:bg-secondary text-foreground"
                                        >
                                            <Settings className="mr-2 h-4 w-4" />
                                            <span>Settings</span>
                                        </Command.Item>
                                    </Command.Group>
                                </Command.List>
                            </Command>
                        </motion.div>
                    </div>
                </React.Fragment>
            )}
        </AnimatePresence>
    );
}
